"use client"

import Link from "next/link";
import { usePathname } from "next/navigation";
import { Gauge, Trophy, Radio, User } from "lucide-react";
import { cn } from "@/lib/utils";

const NAV_ITEMS = [
  { label: "Ranking", icon: Trophy, href: "/leaderboard" },
  { label: "Garë", icon: Gauge, href: "/dashboard", primary: true },
  { label: "Radarët", icon: Radio, href: "/explore" },
  { label: "Profili", icon: User, href: "/profile" },
];

export function BottomNav() {
  const pathname = usePathname();

  return (
    <div className="fixed bottom-0 left-0 right-0 mx-auto max-w-md h-20 glass border-t border-white/10 px-4 flex items-center justify-around z-50 rounded-t-3xl shadow-2xl">
      {NAV_ITEMS.map((item) => {
        const isActive = pathname === item.href;
        const Icon = item.icon;

        if (item.primary) {
          return (
            <Link key={item.href} href={item.href} className="relative -top-6">
              <div className={cn(
                "w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300 neon-glow border-4 border-background",
                isActive ? "bg-accent scale-110" : "bg-primary"
              )}>
                <Icon className={cn("w-8 h-8", isActive ? "text-background" : "text-accent")} />
              </div>
              <span className="text-[10px] absolute -bottom-6 left-1/2 -translate-x-1/2 font-bold uppercase tracking-tighter text-accent">
                {item.label}
              </span>
            </Link>
          );
        }

        return (
          <Link key={item.href} href={item.href} className="flex flex-col items-center gap-1 group">
            <Icon className={cn(
              "w-6 h-6 transition-colors",
              isActive ? "text-accent neon-text" : "text-muted-foreground group-hover:text-foreground"
            )} />
            <span className={cn(
              "text-[10px] font-medium transition-colors",
              isActive ? "text-accent" : "text-muted-foreground"
            )}>
              {item.label}
            </span>
            {isActive && <div className="w-1 h-1 rounded-full bg-accent neon-glow mt-0.5" />}
          </Link>
        );
      })}
    </div>
  );
}
